const Web3 = require('web3');
const ethers = require('ethers');

// Set up web3 connection
const web3 = new Web3(new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/{YOUR_PROJECT_ID}'));

// Set up wallet configuration with private keys for signing transactions
const wallet = new ethers.Wallet('0x' + 'PRIVATE KEY', {
  network: 'mainnet',
  gasPrice: '20000000000',
});

// Function to send ETH
function sendETH(to, amount) {
  const tx = {
    from: wallet.address,
    to,
    value: ethers.utils.parseEther('' + amount),
    gasLimit: 21000,
  };
  return web3.eth.sendTransaction(tx);
}

// Function to interact with smart contracts
function interactWithContract(contractAddress, abi, methodName, ...args) {
  const contract = new ethers.Contract(contractAddress, abi, wallet);
  return contract[methodName](...args);
}

module.exports = { sendETH, interactWithContract };